import React, { useEffect, useMemo, useState } from 'react'
import { sensorService } from '../../services/api'
import '../../styles/technician/technician-sensor.css'
import { SENSOR_ORDER, getSensorProfile, getSensorStatus, getSensorStatusLabel, getSensorTypeKey } from '../../utils/sensorMetrics'
import { useAuth } from '../../context/AuthContext'
import { Line } from 'react-chartjs-2'
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
  Filler,
} from 'chart.js'

ChartJS.register(CategoryScale, LinearScale, PointElement, LineElement, Title, Tooltip, Legend, Filler)

const SENSOR_COLORS = ['#2563eb', '#f97316', '#10b981', '#8b5cf6', '#ef4444', '#14b8a6', '#f59e0b', '#0f766e']

const formatVietnameseDateTime = (value) => {
  if (!value) return '-'
  const date = new Date(value)
  if (Number.isNaN(date.getTime())) return '-'
  return new Intl.DateTimeFormat('vi-VN', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    hour12: false,
    timeZone: 'Asia/Ho_Chi_Minh',
  }).format(date)
}

const formatNumber = (value) => {
  if (value === null || value === undefined || value === '') return '-'
  const number = Number(value)
  if (Number.isNaN(number)) return value
  return (Math.round(number * 100) / 100).toFixed(2)
}

const formatRelativeTime = (value) => {
  if (!value) return '-'
  const now = Date.now()
  const target = new Date(value).getTime()
  if (Number.isNaN(target)) return '-'
  const diffSec = Math.max(0, Math.floor((now - target) / 1000))

  if (diffSec < 60) return `${diffSec} giay truoc`
  const diffMin = Math.floor(diffSec / 60)
  if (diffMin < 60) return `${diffMin} phut truoc`
  const diffHour = Math.floor(diffMin / 60)
  if (diffHour < 24) return `${diffHour} gio truoc`
  const diffDay = Math.floor(diffHour / 24)
  return `${diffDay} ngay truoc`
}

const TIME_RANGE_OPTIONS = [
  { value: '1h', label: '1 gio' },
  { value: '6h', label: '6 gio' },
  { value: '12h', label: '12 gio' },
  { value: '24h', label: '24 gio' },
  { value: '7d', label: '7 ngay' },
]

const buildReadingsMap = (sensorList, pondRealtimeData) => {
  const readingsMap = {}

  sensorList.forEach((sensor) => {
    const directData = pondRealtimeData[sensor.sensor_type]
    const normalizedData = pondRealtimeData[sensor.sensor_type?.toString().toLowerCase()]
    const profile = getSensorProfile(sensor.sensor_type)
    const profileData = profile?.type ? pondRealtimeData[profile.type] : null
    const typeKey = getSensorTypeKey(sensor.sensor_type)
    const typeKeyData = typeKey ? pondRealtimeData[typeKey] : null

    const source = directData || normalizedData || profileData || typeKeyData
    if (source && Array.isArray(source.readings)) {
      readingsMap[sensor.sensor_id] = source.readings
    }
  })

  return readingsMap
}

const TechnicianSensor = () => {
  const { realtimeSensorData, ponds: contextPonds } = useAuth()
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')
  const [selectedPondId, setSelectedPondId] = useState('')
  const [searchTerm, setSearchTerm] = useState('')
  const [typeFilter, setTypeFilter] = useState('ALL')
  const [statusFilter, setStatusFilter] = useState('ALL')
  const [timeRange, setTimeRange] = useState('24h')
  const [isPaused, setIsPaused] = useState(false)
  const [sensors, setSensors] = useState([])
  const [sensorReadings, setSensorReadings] = useState({})

  // Đặt ao ban đầu từ context
  useEffect(() => {
    if (contextPonds.length > 0 && !selectedPondId) {
      setSelectedPondId(String(contextPonds[0].pond_id))
    }
    if (contextPonds.length > 0) {
      setLoading(false)
    }
  }, [contextPonds, selectedPondId])

  // Lấy cảm biến cho ao đã chọn
  useEffect(() => {
    if (!selectedPondId) {
      setSensors([])
      setSensorReadings({})
      return
    }

    const fetchSensorData = async () => {
      try {
        const sensorsRes = await sensorService.getSensorsByPondId(selectedPondId)
        const sensorList = sensorsRes?.data?.data || []
        setSensors(sensorList)
        const pondData = realtimeSensorData[selectedPondId] || {}
        const readingsMap = buildReadingsMap(sensorList, pondData)
        setSensorReadings(readingsMap)
        setError('')
      } catch (err) {
        setError(err?.response?.data?.message || 'Không tải được dữ liệu cảm biến')
        setSensors([])
        setSensorReadings({})
      }
    }

    fetchSensorData()
  }, [selectedPondId])

  useEffect(() => {
    if (!selectedPondId || isPaused || sensors.length === 0) {
      return
    }
    const pondData = realtimeSensorData[selectedPondId] || {}
    const readingsMap = buildReadingsMap(sensors, pondData)
    setSensorReadings(readingsMap)
  }, [selectedPondId, realtimeSensorData, isPaused, sensors])

  const selectedPond = contextPonds.find((pond) => String(pond.pond_id) === String(selectedPondId))

  const sensorStats = useMemo(() => {
    const stats = {}
    sensors.forEach((sensor) => {
      const readings = sensorReadings[sensor.sensor_id] || []
      const latest = readings.length > 0 ? readings[readings.length - 1] : null
      if (latest && latest.value !== null && latest.value !== undefined) {
        const typeKey = getSensorTypeKey(sensor.sensor_type) || sensor.sensor_type?.toString().toLowerCase()
        if (!stats[typeKey]) {
          const profile = getSensorProfile(sensor.sensor_type)
          stats[typeKey] = {
            type: typeKey,
            value: latest.value,
            updatedAt: latest.recorded_at,
            status: getSensorStatus(latest.value, sensor.sensor_type),
            profile,
          }
        }
      }
    })
    return stats
  }, [sensors, sensorReadings])

  const latestRealtimeSensors = useMemo(
    () => sensors.map((sensor, index) => {
      const readings = sensorReadings[sensor.sensor_id] || []
      const latest = readings.length > 0 ? readings[readings.length - 1] : null
      return { sensor, readings, latest, color: SENSOR_COLORS[index % SENSOR_COLORS.length] }
    }),
    [sensors, sensorReadings]
  )

  const latestRows = useMemo(
    () => latestRealtimeSensors.map((entry) => {
      const profile = getSensorProfile(entry.sensor.sensor_type)
      const status = entry.latest ? getSensorStatus(entry.latest.value, entry.sensor.sensor_type) : 'normal'
      return {
        ...entry,
        profile,
        status,
      }
    }),
    [latestRealtimeSensors]
  )

  const totalActiveSensors = useMemo(
    () => latestRows.filter((item) => item.latest && item.sensor.status === 'ACTIVE').length,
    [latestRows]
  )

  const totalAlerts = useMemo(
    () => latestRows.filter((item) => item.latest && ['high', 'low'].includes(item.status)).length,
    [latestRows]
  )

  const latestUpdatedAt = useMemo(() => {
    const timestamps = latestRows
      .map((item) => (item.latest ? new Date(item.latest.recorded_at).getTime() : null))
      .filter((value) => Number.isFinite(value))
    if (timestamps.length === 0) return null
    return new Date(Math.max(...timestamps))
  }, [latestRows])

  const filteredRows = useMemo(() => {
    const normalizedSearch = searchTerm.trim().toLowerCase()
    return latestRows.filter((item) => {
      const typeKey = getSensorTypeKey(item.sensor.sensor_type)
      const typeMatched = typeFilter === 'ALL' || String(typeFilter) === String(typeKey)
      const statusMatched = statusFilter === 'ALL' || statusFilter === item.status
      const searchMatched =
        !normalizedSearch ||
        String(item.sensor.sensor_name || '').toLowerCase().includes(normalizedSearch) ||
        String(item.sensor.serial_number || '').toLowerCase().includes(normalizedSearch) ||
        String(item.profile?.label || '').toLowerCase().includes(normalizedSearch)

      return typeMatched && statusMatched && searchMatched
    })
  }, [latestRows, searchTerm, typeFilter, statusFilter])

  const realtimeChartData = useMemo(() => {
    const datasets = []
    const isoSet = new Set()
    const isoToLabel = new Map()
    const now = Date.now()
    const rangeMap = {
      '1h': 60 * 60 * 1000,
      '6h': 6 * 60 * 60 * 1000,
      '12h': 12 * 60 * 60 * 1000,
      '24h': 24 * 60 * 60 * 1000,
      '7d': 7 * 24 * 60 * 60 * 1000,
    }
    const threshold = now - (rangeMap[timeRange] || rangeMap['24h'])

    latestRealtimeSensors.forEach((entry) => {
      const readings = entry.readings || []
      const ordered = [...readings]
      ordered.forEach((reading) => {
        const time = new Date(reading.recorded_at).getTime()
        if (!Number.isFinite(time) || time < threshold) return
        const iso = new Date(time).toISOString()
        if (!isoToLabel.has(iso)) isoToLabel.set(iso, formatVietnameseDateTime(reading.recorded_at))
        isoSet.add(iso)
      })
    })

    const isoLabels = Array.from(isoSet).sort()
    const labels = isoLabels.map((iso) => isoToLabel.get(iso) || iso)

    latestRealtimeSensors.forEach((entry) => {
      const readings = entry.readings || []
      const map = new Map()
      readings.forEach((r) => {
        const time = new Date(r.recorded_at).getTime()
        if (!Number.isFinite(time) || time < threshold) return
        const iso = new Date(time).toISOString()
        map.set(iso, r.value)
      })

      const data = isoLabels.map((iso) => (map.has(iso) ? Number(map.get(iso)) : null))

      datasets.push({
        label: entry.sensor.sensor_name || entry.sensor.serial_number || `Sensor ${entry.sensor.sensor_id}`,
        data,
        borderColor: entry.color,
        backgroundColor: `${entry.color}22`,
        tension: 0.35,
        fill: true,
        pointRadius: 2,
      })
    })

    return { labels, datasets }
  }, [latestRealtimeSensors, timeRange])

  const handleExportCsv = () => {
    const headers = ['Thoi gian', 'Cam bien', 'Ao nuoi', 'Gia tri', 'Don vi', 'Trang thai']
    const rows = filteredRows.map((item) => {
      const value = item.latest ? formatNumber(item.latest.value) : '-'
      return [
        item.latest ? formatVietnameseDateTime(item.latest.recorded_at) : '-',
        item.sensor.sensor_name || `Cam bien ${item.sensor.sensor_id}`,
        selectedPond ? `${selectedPond.pond_code} - ${selectedPond.pond_name}` : '-',
        value,
        item.profile?.unit || '-',
        getSensorStatusLabel(item.status).replace('⚠️ ', '').replace('✓ ', ''),
      ]
    })

    const csvContent = [headers, ...rows]
      .map((line) => line.map((cell) => `"${String(cell || '').replace(/"/g, '""')}"`).join(','))
      .join('\n')

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' })
    const url = URL.createObjectURL(blob)
    const link = document.createElement('a')
    link.href = url
    link.setAttribute('download', 'technician-realtime-sensors.csv')
    document.body.appendChild(link)
    link.click()
    document.body.removeChild(link)
    URL.revokeObjectURL(url)
  }

  const chartOptions = {
    responsive: true,
    plugins: { legend: { display: true, position: 'bottom' } },
    scales: { y: { beginAtZero: false, ticks: { callback: (v) => String(Math.round(v * 100) / 100) } } },
  }

  return (
    <div className="staff-sensor-page">
      <div className="staff-sensor-header">
        <h1>Dữ liệu cảm biến realtime</h1>
        <p>Theo dõi dữ liệu cảm biến ao tôm theo thời gian thực</p>
      </div>

      {error && <div className="staff-sensor-alert error">{error}</div>}

      {loading ? (
        <div className="staff-sensor-card">
          <p>Đang tải dữ liệu...</p>
        </div>
      ) : (
        <>
          <div className="staff-sensor-controls">
            <label htmlFor="selectedPond">Ao giamsat:</label>
            <select id="selectedPond" value={selectedPondId} onChange={(e) => setSelectedPondId(e.target.value)}>
              <option value="">-- Chon ao --</option>
              {contextPonds.map((pond) => (
                <option key={pond.pond_id} value={pond.pond_id}>
                  {pond.pond_code} - {pond.pond_name}
                </option>
              ))}
            </select>
            <button className="staff-sensor-btn secondary" type="button" onClick={handleExportCsv}>
              Xuat du lieu
            </button>
            <button
              className="staff-sensor-btn primary"
              type="button"
              onClick={() => setIsPaused((prev) => !prev)}
            >
              {isPaused ? 'Resume Live Updates' : 'Pause Live Updates'}
            </button>
          </div>

          <div className="staff-sensor-summary-grid">
            <article className="summary-card">
              <div className="summary-icon">(( ))</div>
              <div>
                <p>Tong cam bien dang hoat dong</p>
                <h3>{totalActiveSensors}</h3>
              </div>
            </article>
            <article className="summary-card">
              <div className="summary-icon">Ao</div>
              <div>
                <p>Ao nuoi dang giam sat</p>
                <h3>{contextPonds.length}</h3>
              </div>
            </article>
            <article className="summary-card">
              <div className="summary-icon">!</div>
              <div>
                <p>Canh bao hien tai</p>
                <h3>{totalAlerts}</h3>
              </div>
            </article>
            <article className="summary-card">
              <div className="summary-icon">T</div>
              <div>
                <p>Thoi gian cap nhat gan nhat</p>
                <h3>{formatRelativeTime(latestUpdatedAt)}</h3>
              </div>
            </article>
          </div>

          {selectedPond && (
            <div className="staff-sensor-card pond-card">
              <h2>{selectedPond.pond_code} - {selectedPond.pond_name}</h2>
              <p className="staff-sensor-pond-info">Dien tich: {selectedPond.area_m2} m2 | Do sau: {selectedPond.depth_m} m | Trang thai: {selectedPond.status}</p>
            </div>
          )}

          {sensors.length === 0 ? (
            <div className="staff-sensor-card">
              <p className="staff-sensor-empty">Ao này chưa có cảm biến.</p>
            </div>
          ) : (
            <>
              <div className="staff-sensor-grid">
                {SENSOR_ORDER.map((key) => {
                  const sensorInfo = getSensorProfile(key)
                  const stat = sensorStats[key]
                  const status = stat?.status || 'normal'
                  return (
                    <div key={key} className={`staff-sensor-card sensor-card compact status-${status}`}>
                      <div className="sensor-icon">{sensorInfo.icon}</div>
                      <div className="sensor-info">
                        <h3>{sensorInfo.label}</h3>
                        <div className="sensor-value">
                          {stat ? formatNumber(stat.value) : '-'}
                          {sensorInfo.unit && <span className="sensor-unit">{sensorInfo.unit}</span>}
                        </div>
                        <div className="sensor-time">
                          {stat ? formatRelativeTime(stat.updatedAt) : 'chua co du lieu'}
                        </div>
                        <div className={`sensor-status status-${status}`}>
                          {getSensorStatusLabel(status)}
                        </div>
                      </div>
                    </div>
                  )
                })}
              </div>

              <div className="staff-sensor-card chart-card">
                <div className="chart-header">
                  <h3>Recent Sensor Data</h3>
                  <div className="time-range-tabs">
                    {TIME_RANGE_OPTIONS.map((option) => (
                      <button
                        key={option.value}
                        type="button"
                        className={`time-range-tab ${timeRange === option.value ? 'active' : ''}`}
                        onClick={() => setTimeRange(option.value)}
                      >
                        {option.label}
                      </button>
                    ))}
                  </div>
                </div>
                {realtimeChartData.datasets.length > 0 ? (
                  <Line data={realtimeChartData} options={chartOptions} />
                ) : (
                  <div className="staff-sensor-chart-empty">Chua co du lieu realtime</div>
                )}
              </div>

              <div className="staff-sensor-card">
                <div className="table-toolbar">
                  <div className="table-search-wrap">
                    <span>⌕</span>
                    <input
                      type="text"
                      placeholder="Tim kiem cam bien..."
                      value={searchTerm}
                      onChange={(e) => setSearchTerm(e.target.value)}
                    />
                  </div>
                  <select value={typeFilter} onChange={(e) => setTypeFilter(e.target.value)}>
                    <option value="ALL">All Sensor Types</option>
                    {SENSOR_ORDER.map((type) => {
                      const profile = getSensorProfile(type)
                      return (
                        <option key={type} value={type}>
                          {profile?.label || type}
                        </option>
                      )
                    })}
                  </select>
                  <select value={statusFilter} onChange={(e) => setStatusFilter(e.target.value)}>
                    <option value="ALL">All Statuses</option>
                    <option value="normal">Binh thuong</option>
                    <option value="low">Thap</option>
                    <option value="high">Cao</option>
                  </select>
                </div>

                <div className="staff-sensor-table-wrap">
                  <table>
                    <thead>
                      <tr>
                        <th>Thoi gian</th>
                        <th>Cam bien</th>
                        <th>Ao nuoi</th>
                        <th>Gia tri</th>
                        <th>Don vi</th>
                        <th>Trang thai</th>
                      </tr>
                    </thead>
                    <tbody>
                      {filteredRows.map((item) => {
                        const value = item.latest?.value
                        return (
                          <tr key={item.sensor.sensor_id}>
                            <td>{item.latest ? formatVietnameseDateTime(item.latest.recorded_at) : '-'}</td>
                            <td>{item.sensor.sensor_name || `Cam bien ${item.sensor.sensor_id}`}</td>
                            <td>{selectedPond ? `${selectedPond.pond_code} - ${selectedPond.pond_name}` : '-'}</td>
                            <td>
                              {value !== null && value !== undefined ? formatNumber(value) : '-'}
                            </td>
                            <td>{item.profile?.unit || '-'}</td>
                            <td>
                              <span className={`badge status-${item.status}`}>
                                {getSensorStatusLabel(item.status).replace('⚠️ ', '').replace('✓ ', '')}
                              </span>
                            </td>
                          </tr>
                        )
                      })}
                      {filteredRows.length === 0 && (
                        <tr>
                          <td colSpan="6" className="staff-sensor-empty">Khong co du lieu phu hop</td>
                        </tr>
                      )}
                    </tbody>
                  </table>
                </div>
              </div>
            </>
          )}
        </>
      )}
    </div>
  )
}

export default TechnicianSensor
